  if (!record) return res.status(400).json({ error: 'invalid_grant', error_description: 'Unknown code' });
  if (record.used) return res.status(400).json({ error: 'invalid_grant', error_description: 'Code already used' });
  if (Date.now() > record.expires_at) return res.status(400).json({ error: 'invalid_grant', error_description: 'Code expired' });
  if (record.client_id !== client_id) return res.status(400).json({ error: 'invalid_grant', error_description: 'Client mismatch' });
  if (record.redirect_uri !== redirect_uri) return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });

  record.used = true;
  authorizationCodes.set(code, record);

